/**
 * A real 2 x 2 JPEG produced by the platform image encoder.
 *
 * Keep this as valid image data: camera regressions must not use arbitrary text
 * with an image MIME prefix because browser decoders correctly reject it.
 */
export const VALID_2X2_JPEG_BASE64 =
  '';

export const VALID_2X2_JPEG_DATA_URI =
  `data:image/jpeg;base64,${VALID_2X2_JPEG_BASE64}`;

export const VALID_2X2_JPEG_BYTES = Uint8Array.from(
  Buffer.from(VALID_2X2_JPEG_BASE64, 'base64'),
);
